long long Read()  {

	long long val = 0, opt = 1; char ch;

	while (!isdigit(ch = getchar() )) if (ch == '-') opt = -1;

	while (isdigit( ch )) (val *= 10) += ch - '0', ch= getchar();

	return val * opt;

}



