using namespace std;



using ll = long long;



const ll inf = 1e18;

const int MX = 100005;



ll dn[MX * 4], sum[MX * 4];

ll a[MX];



void add(int u, int st, int en, ll c) {

	sum[u] = c;

	dn[u] = c;

}



void down(int u, int st, int en) {

	if (!dn[u]) return;

	int md = st + en >> 1;

	add(u * 2, st, md, dn[u]);

	add(u * 2 + 1, md + 1, en, dn[u]);

	dn[u] = 0;

}

void update(int u) {

	sum[u] = min(sum[u * 2], sum[u * 2 + 1]);

}

void add(int u, int st, int en, int l, int r, ll c) {

	if (l <= st && en <= r) {

		add(u, st, en, c);

		return;

	}

	down(u, st, en);

	int md = st + en >> 1;

	if (l <= md) add(u * 2, st, md, l, r, c);

	if (r > md) add(u * 2 + 1, md + 1, en, l, r, c);

	update(u);

}

ll get(int u, int st, int en, int l, int r) {

	if (l <= st && en <= r) {

		return sum[u];

	}

	down(u, st, en);

	int md = st + en >> 1;

	ll rlt = inf;

	if (l <= md) rlt = min(rlt,  get(u * 2, st, md, l, r));

	if (r > md) rlt = min(rlt, get(u * 2 + 1, md + 1, en, l, r));

	update(u);

	return rlt;

}

void build(int u, int st, int en) {

	dn[u] = 0;

	if (st == en) {

		sum[u] = a[st];

		return;

	}

	int md = st + en >> 1;

	build(u * 2, st, md);

	build(u * 2 + 1, md + 1, en);

	update(u);

}



struct p{

	int l, r, c;

	bool operator < (p rhs){

		if(rhs.r == r) return l < rhs.l;

		return r < rhs.r;

	}

};

p q[100005];



int main() {

	ios::sync_with_stdio(0);

	int n, m;

	cin >> n >> m;

